var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"하아, 하……!","JPN":"はぁ、は……！","ENG":"*Huff...* *Huff...*","TWN":"哈啊，哈……！"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_CA_NULL","text":{"KOREA":"저도 같이 어울려도 될까요, 미나 양?","JPN":"僕もまざっていいですか、ミナさん？","ENG":"Mind if I join you, Mina?","TWN":"可以帶我一個嗎，米娜？"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"선배! 서윤은?!","JPN":"先輩！　シズカは！？","ENG":"Shiyoon! What about Seo Yoon?!","TWN":"前輩！徐芸呢？！"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_CA_NULL","text":{"KOREA":"간병인까지 필요하진 않다고 하시더군요.","JPN":"看病人は必要ないとのことです。","ENG":"She insisted that she didn't need any caretakers.","TWN":"她說不需要看護。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_CA_NULL","text":{"KOREA":"그보다 지금 미나 양의 관심이 필요한 분은 따로 있지 않나요?","JPN":"それより今ミナさんが気にかけなければいけない方は他にいるんじゃないですか？","ENG":"Moreover, isn't there someone else you should be paying attention to?","TWN":"比起這個，現在米娜需要在意的另有其人吧？"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"그건 말 안 해 줘도 알고 있어!","JPN":"そんなの言われなくたってわかってるよ！","ENG":"I know that already!","TWN":"不用你說我也知道！"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"내 말 똑바로 들어, 레이 선배!","JPN":"私の言う事をよく聞いて、レイ先輩！","ENG":"Listen, Ray!","TWN":"你給我聽好了，雷伊！"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"마왕인지 뭔지 내가 알 바 아니야!","JPN":"魔王が何だとか、私はどうでもいい！","ENG":"I don't care about the Demon Lord or whatever!","TWN":"我不管是魔王還是什麼！"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"그런 아무래도 좋을 얘기에 신경 쓰긴 이제 지긋지긋하다고!","JPN":"そんなどうでもいい話に気を使うのなんて、もううんざりだよ！","ENG":"I'm sick and tired of those pointless stories!","TWN":"那種毫無意義的話，我已經聽夠了！"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_B","text":{"KOREA":"당신에게는 아무래도 좋을 얘기가 아닐 텐데요.","JPN":"あなたにとってはどうでもいい話ではありませんよ。","ENG":"It’s not pointless to you.","TWN":"對你來說應該不是毫無意義吧？"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_B","text":{"KOREA":"마왕도, 클리포트 게임도…… 전부 이 세상을 지탱하는 규칙의 일부입니다.","JPN":"魔王も、クリフォトゲームも……すべてこの世界を支えるルールの一部です。","ENG":"The Demon Lord, the Qliphoth Game... They are all part of the rules that hold this world together.","TWN":"魔王，逆卡巴拉遊戲……都是支撐這個世界的規則的一部分。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"누가 그런 기분 나쁜 규칙을 정한 건데!","JPN":"誰がそんな訳のわからないルールを決めたの！？","ENG":"And who the heck set these damn rules?!","TWN":"是誰定了那種讓人不爽的規則啊！"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_DESPAIR"}}}},{"id":"L23_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"그런 규칙을 강요하는 녀석이 있으면 쓰러뜨려야 하는 거 아니야?!","JPN":"そんなルールを押し付けてくる奴がいるなら、倒すべきでしょ！？","ENG":"If there's someone who forces us to follow these rules, shouldn't it be them that we're fighting against?!","TWN":"如果有人強迫你遵循這種規則，難道不應該打倒他嗎？！"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_DESPAIR"}}}},{"id":"L24_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_B","text":{"KOREA":"아무것도 모르면서……!","JPN":"何も知らないくせに……！","ENG":"You know nothing...!","TWN":"你……！"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_B","text":{"KOREA":"자기가 모르는 일까지 함부로 말하지 마세요!","JPN":"勝手なこと言わないでください！","ENG":"Don’t act like you know what you’re talking about!","TWN":"你還是什麼都不懂！"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_SERIOUS"}}}},{"id":"L27_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"큭……! 진짜……!","JPN":"クッ……！　もう……！","ENG":"Kgh...! Come on...!","TWN":"咳……！真是的……！"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_CUTSCEN_BOOM"},{"id":"L28_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"그렇다면 알아들을 수 있게 설명이라도 해!","JPN":"じゃあ、わかるように説明してよ！","ENG":"Then explain so that I can understand, for goodness sake!","TWN":"那你就解釋到讓我懂啊！"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"소대장도, 레이 선배도! 왜 다들 중요한 건 감추고 알려 주는데!","JPN":"小隊長も、レイ先輩も！　何でみんな大事なところは教えてくれないんだよ！","ENG":"The Commander! You, Ray! Why does everyone always keep important secrets from me?!","TWN":"小隊長也是，雷伊前輩也是！為什麼你們都要對我隱瞞！"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_B","text":{"KOREA":"당신에게는 침묵이 더 나은 답이니까요!","JPN":"あなたには何も言わない方がいいからです！","ENG":"Because not knowing is better than the truth!","TWN":"因為對你來說，沉默才是更好的答案！"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_B","text":{"KOREA":"진실을 알아 봤자 소용없어요! 모르는 편이 더 행복할 거란 말입니다!","JPN":"真実を知ったとしても何もいいことはない！　知らない方が幸せなんです！","ENG":"There’s no point! You’ll be happier not knowing!","TWN":"知道真相有什麼用！不知道的人反而更幸福！"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"걱정해 주는 척 하지 마! 레이 선배는 그냥 아카데미에서처럼 겁내고 피할 뿐이잖아!","JPN":"私のためみたいな言い方はやめてよ！　レイ先輩はただアカデミーでの時みたいに、恐れて、逃げているだけじゃない！","ENG":"Stop acting like you care! You're nothing but a coward, like you were back at the academy!","TWN":"別裝出一副很關心我的樣子！和在學院時一樣，雷伊前輩只是在害怕和逃避罷了！"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"마왕이니까! 세상의 적이니까! 언제 헤어질지 모르니까!","JPN":"魔王だから！　世界の敵だから！　いつ別れてもおかしくないから！","ENG":"Ooh, I'm the Demon Lord! The world's enemy! Parting is inevitable for someone like me!","TWN":"“噢——我是魔王！我是世界的敵人！分離對我這種人來說是必定的！”"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_B","text":{"KOREA":"윽……?","JPN":"うっ……？","ENG":"Ugh...?!","TWN":"呃……？"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"내 손으로 죽여 달라는 게 날 위해서라고?!","JPN":"私に殺されるのが、私のため！？","ENG":"You say that me killing you is for my own sake?!","TWN":"讓我親手殺了你？為了我好？"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"그게 자기 선택이 책임지기 무서워서 도와 달라는 거밖에 더 돼?!","JPN":"そんなの自分で責任取るのが怖いから、私にやらせようとしているだけでしょ！？","ENG":"How is that different from avoiding responsibility for the choices you've made?!","TWN":"你就是害怕為自己的選擇負責才找我幫忙的吧，除此之外還有別的原因嗎？！"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_B","text":{"KOREA":"저는, 그런 게……!","JPN":"僕は、そんなんじゃ……！","ENG":"It's, not–!","TWN":"不是，我……！"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_B","text":{"KOREA":"웃?!","JPN":"うっ！？","ENG":"Ugh?!","TWN":"呃？！"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_SURPRISE"}}},"sfx":"FX_COMBAT_ALL_SWORD_SLASH_BIG_02"},{"id":"L45_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_CA_NULL","text":{"KOREA":"허점입니다! 지금이에요, 서윤 양!","JPN":"隙ありです！　今です、シズカさん！","ENG":"An opening! Now, Seo Yoon!","TWN":"有破綻！就是現在，徐芸！"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"SEO_YOON_ALT_CA_NULL","text":{"KOREA":"구구절절한 하소연은 충분히 들었어.","JPN":"だらだらとした泣き言はもうたくさん聞いたわ。","ENG":"I've heard enough of this and that about your pathetic life.","TWN":"我們已經聽夠你訴苦了。"},"stage":{"bg":"MAINSTREAM_5302010","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_SYS_RUNNING"},{"id":"L49_1","type":"dialog","speaker":"SEO_YOON_ALT_CA_NULL","text":{"KOREA":"하지만 미나가 싫다는데 그렇게 매달리는 건 신사적이지 않잖아?","JPN":"でもミナは嫌だって言っているのに、しがみつくのは紳士的じゃないわね？","ENG":"It’s not very polite of you to cling on when Mina already said no.","TWN":"米娜都說不要了，你卻還死皮賴臉地纏著她，這就有點不夠紳士了吧？"},"stage":{"bg":"MAINSTREAM_5302010","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L50_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_B","text":{"KOREA":"이 기운은…… 미스틸테인?","JPN":"この気は……ミスティルテイン？","ENG":"This energy... Is it Misteltein?","TWN":"這股氣息……是米斯特丁？"},"stage":{"bg":"MAINSTREAM_5302010","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L1_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_B","text":{"KOREA":"하지만 본래 위력을 어떻게……!?","JPN":"でもどうやって本来の威力を……！？","ENG":"But how did you bring out its full power...?!","TWN":"你們是怎樣發揮它本來的威力的……！？"},"stage":{"bg":"MAINSTREAM_5302010","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L2_1","type":"dialog","speaker":"SEO_YOON_ALT_CA_NULL","text":{"KOREA":"오늘은 세 사람 덕분에 클리포트 인자를 듬뿍 머금었으니까 평소보다 많이 아플 거야.","JPN":"今日は三人が戦ってくれたおかげでクリフォトファクターがたっぷり集まったから、いつもより少し痛いわよ。","ENG":"I've gathered the Qliphoth Factors enough today, thanks to you three. Careful, it's gonna hurt– A LOT.","TWN":"托你們三個人的福，今天它吸飽了逆卡巴拉因子，所以會比平時更，疼，喔。"},"stage":{"bg":"MAINSTREAM_5302010","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"SEO_YOON_ALT_CA_NULL","text":{"KOREA":"한동안 침대에 누워서 머리 좀 식히시지, 마왕님.","JPN":"しばらくベッドの上で頭を冷やしなさい、魔王さん。","ENG":"Get some good rest lying in bed, Mr. Demon Lord.","TWN":"你在床上躺一陣子，好好冷靜一下吧，魔王。"},"stage":{"bg":"MAINSTREAM_5302010","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_CA_NULL","text":{"KOREA":"통한 건가요?","JPN":"効いたんでしょうか？","ENG":"Did it work?","TWN":"起作用了嗎？"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEO_YOON_ALT_CA_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L11_1","type":"dialog","speaker":"SEO_YOON_ALT_CA_NULL","text":{"KOREA":"치잇…….","JPN":"チッ……","ENG":"Tsk...","TWN":"嘖……"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEO_YOON_ALT_CA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L12_1","type":"dialog","speaker":"SEO_YOON_ALT_CA_NULL","text":{"KOREA":"실패야. 저 여자가 갑자기 사선에 끼어드는 바람에……","JPN":"失敗よ。あの女が急に射線に飛び込んできたせいで……","ENG":"No. That woman suddenly got in the way...","TWN":"失敗了，那個女人突然插手……"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEO_YOON_ALT_CA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L14_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"큭…… 커, 흑……!","JPN":"クッ……カ、カハッ……！","ENG":"Kgh... Urgh...!","TWN":"咳……咳，呵……！"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L15_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_B","text":{"KOREA":"루, 루크레시아? 여긴 어떻게……?","JPN":"る、ルクレシア？　どうやってここに……？","ENG":"L-Lucrecia! How did you...?!","TWN":"露，露可蕾西亞？你怎麼會在這裡……？"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"구원자님을 모시는 것이…… 제 소명이니까요.","JPN":"救世主様に仕えるのが……私の使命ですから。","ENG":"It is my duty... to serve you... Savior.","TWN":"因為侍奉救贖者大人……是我的使命。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"구원자님의 손을 더럽히는 건……. 저희를 위해 마왕과 손잡은 그 날 한 번이면 충분해요.","JPN":"救世主様がお手を汚されるのは……私たちのために魔王と手を組んだあの日だけで十分です。","ENG":"You need not shed any more blood... After the day you decided to take the Demon Lord's offer for us.","TWN":"弄髒救贖者大人雙手的這種事……有變成魔王的那一次就夠了。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"그러니 저들은, 제게 맡겨 주세요. 구원자님.","JPN":"ですからあの者たちは、私にお任せください。救世主様。","ENG":"So please, leave them to me. Savior.","TWN":"所以，請把他們交給我吧，救贖者大人。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_B","text":{"KOREA":"무슨 소리야! 그런 상처로는 오래 싸우지도 못해!","JPN":"何を言っているんだ！　その怪我じゃあまり持たない！","ENG":"No way! You're not going to last a minute with a wound like that!","TWN":"你在說什麼！你傷成那樣，撐不了太久的！"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"아뇨. 미숙한 늑대를 상대하기엔……","JPN":"いいえ。未熟な狼が相手なら……","ENG":"I beg to differ. Dealing with this yet immature Wolf...","TWN":"不，對付不成熟的狼……"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"제 힘만으로도 충분해요……!","JPN":"私の力だけで十分です……！","ENG":"It's going to be enough with my powers alone...!","TWN":"光靠我的力量就足夠了……！"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};